import { ComponentModule } from '@/main';
import { TOAST_TRIGGER } from '@/models/events';
import { SSO } from '@/models/sso';
import { ToastError } from '@/models/toast';
import { authenticate, isAuthenticated, logout } from '@/services/auth.service';

export default {
    name: () => 'login',
    template: () => import('./login.html?raw'),
    data: () => ({
        loading: true,
        submitting: false,
        async init() {
            console.log('login@init');
            await this.handleSSORequest();

            // There is a middleware that will redirect if the user is authenticated
            const isLoggedIn = await isAuthenticated();

            this.loading = isLoggedIn;
        },

        async handleSSORequest(): Promise<void> {
            // This is a placeholder for handling SSO requests
            // For example, if the SSO is enabled, we can redirect to the SSO page

            const sso = Number.parseInt(this.$router.params.sso || '0');

            if (sso === SSO.USER_PASSWORD) {
                this.loading = true;
                await logout();

                const username: string = this.$router.params.username ?? '';
                const password: string = this.$router.params.password ?? '';

                await this.login(username, password);
            }
        },

        async submit(e: SubmitEvent) {
            try {
                console.log('login@submit');
                this.submitting = true;

                /** @ts-expect-error 2339 */
                const username = e.target?.username?.value;
                /** @ts-expect-error 2339 */
                const password = e.target?.password?.value;

                if (!username || !password) {
                    throw new Error('Username and password are required');
                }

                await this.login(username, password);
            } catch (error: any) {
                console.error(error);
                this.submitting = false;
            }
        },
        async login(username: string, password: string): Promise<void> {
            const { success, user, message } = await authenticate(username, password);

            this.$nextTick(() => {
                console.log('login@isAuthenticated', user);

                if (!success) {
                    this.$dispatch(TOAST_TRIGGER, { msg: message, level: ToastError });

                    this.submitting = false;
                    return;
                }

                this.$router.navigate('/');
            });
        },
    }),
} as ComponentModule;
